module top_module(
  input [7:0] in1,
  input [7:0] in2,
  output reg match
);reg [7:0] bitwise_not_temp;
  integer i;

  always @* begin
    match = 1;
    for (i = 0; i < 8; i = i + 1) begin
      bitwise_not_temp[i] = (in1[i] == in2[i]);
      match = match & bitwise_not_temp[i];
    end
  end

endmodule
